def _get_db():
    """
    Get database connection respecting Config.DATABASE_TYPE.
    Supports both PostgreSQL and SQLite.
    """
    from config import Config
    if Config.DATABASE_TYPE == 'postgresql':
        import psycopg2
        from psycopg2.extras import RealDictCursor
        return psycopg2.connect(
            Config.get_db_connection_string(),
            cursor_factory=RealDictCursor
        ), '%s'
    else:
        import sqlite3
        conn = sqlite3.connect(Config.SQLITE_DB)
        conn.row_factory = sqlite3.Row
        return conn, '?'


def _row_to_dict(row):
    """Convert DB row to plain dict (works for both psycopg2 and sqlite3)."""
    if row is None:
        return None
    if isinstance(row, dict):
        return row
    return dict(row)



# ── Institutional Score Utility ────────────────────────────────────────────────

def compute_institutional_score(company_data: dict) -> dict:
    """
    Compute an institutional quality/complexity score for a company.
    Wraps InstitutionalValuationEngine using available company_data fields.
    Returns a dict with: quality_score (0-1), complexity, confidence, wacc_suggestion.
    """
    try:
        from institutional_valuation_engine import InstitutionalValuationEngine, CompanyProfile

        revenue = float(company_data.get('revenue') or 0)
        ebitda = float(company_data.get('ebitda') or 0)
        market_cap = float(company_data.get('market_cap_estimate') or 0)
        debt = float(company_data.get('debt') or 0)
        cash = float(company_data.get('cash') or 0)
        beta = float(company_data.get('beta') or 1.0)
        growth_1y = float(company_data.get('growth_rate_y1') or 0.05)
        terminal_g = float(company_data.get('terminal_growth') or 0.025)
        profit_margin = float(company_data.get('profit_margin') or 0.10)
        capex_pct = float(company_data.get('capex_pct') or 0.05)

        ebitda_margin = (ebitda / revenue) if revenue > 0 else 0.15
        net_ev = market_cap + debt - cash
        leverage = (debt - cash) / ebitda if ebitda > 0 else 1.0

        profile = CompanyProfile(
            name=company_data.get('name', 'Unknown'),
            sector=company_data.get('sector', 'Technology'),
            revenue=revenue,
            market_cap=market_cap,
            enterprise_value=net_ev,
            ebitda_margin=ebitda_margin,
            operating_margin=ebitda_margin * 0.85,
            net_margin=profit_margin,
            roe=0.15,
            roic=0.12,
            revenue_growth_3y_cagr=growth_1y,
            revenue_growth_1y=growth_1y,
            expected_growth_3y=growth_1y * 0.85,
            fcf_conversion=0.85,
            cash_conversion_cycle=45,
            asset_turnover=0.8,
            leverage_ratio=max(0, leverage),
            interest_coverage=max(1, ebitda / max(1, debt * 0.05)),
            volatility=beta,
            capex_to_revenue=capex_pct,
            capex_to_depreciation=1.2,
            working_capital_intensity=0.05,
        )

        engine = InstitutionalValuationEngine()
        quality_score = engine._calculate_quality_score(profile)
        complexity = engine.determine_valuation_complexity(profile)
        confidence = engine._calculate_confidence(quality_score, 5)

        wacc_dict = engine.derive_discount_rate(profile, [])
        growth_dict = engine.derive_growth_assumptions(profile, [])

        return {
            'quality_score': round(quality_score, 3),
            'quality_grade': 'A' if quality_score > 0.75 else 'B' if quality_score > 0.55 else 'C' if quality_score > 0.35 else 'D',
            'complexity': complexity.value,
            'confidence': confidence,
            'suggested_wacc': round(wacc_dict.get('wacc', 0.09), 4),
            'suggested_terminal_growth': round(growth_dict.get('terminal_growth', 0.025), 4),
            'wacc_rationale': wacc_dict.get('rationale', ''),
        }
    except Exception as e:
        logger.warning(f'Institutional score failed: {e}')
        return {
            'quality_score': None,
            'error': str(e),
        }


def register_axiom_routes(app):
    """Register all AXIOM Phase 1-5 routes on the Flask app."""

    # ── Macro / FRED Rates ────────────────────────────────────────────────────

    @app.route('/api/macro/rates', methods=['GET'])
    def get_macro_rates():
        """Return live macro rates from FRED (with 4h cache). Graceful fallback."""
        try:
            from data_layer import DataLayer
            dl = DataLayer()
            rates_raw = dl.get_macro_rates()
            rates = {}
            for key, result in rates_raw.items():
                rates[key] = {
                    'value': result.value,
                    'source': result.source,
                    'available': result.available,
                    'gap_reason': result.gap_reason,
                }
            return jsonify({'rates': rates, 'fetched_at': datetime.utcnow().isoformat()})
        except Exception as e:
            logger.error(f'Error fetching macro rates: {e}')
            return jsonify({'error': str(e), 'rates': {}}), 500

    # ── Company Financials (EDGAR) ────────────────────────────────────────────

    @app.route('/api/company/<int:company_id>/financials', methods=['GET'])
    def get_company_edgar_financials(company_id):
        """Fetch company financials from SEC EDGAR XBRL with source attribution."""
        try:
            conn, ph = _get_db()
            cur = conn.cursor()
            cur.execute(f'SELECT name, sector FROM companies WHERE id = {ph}', (company_id,))
            row = _row_to_dict(cur.fetchone())
            conn.close()

            if not row:
                return jsonify({'error': f'Company {company_id} not found'}), 404

            ticker = request.args.get('ticker', row['name'].split()[0].upper())

            from data_layer import DataLayer
            dl = DataLayer()
            result = dl.get_company_financials(ticker)

            return jsonify({
                'company_id': company_id,
                'ticker': ticker,
                'data': result.value,
                'source': result.source,
                'available': result.available,
                'gap_reason': result.gap_reason,
                'fetched_at': result.fetched_at.isoformat(),
            })
        except Exception as e:
            logger.error(f'EDGAR financials failed for company {company_id}: {e}')
            return jsonify({'error': str(e)}), 500

    # ── LBO Analysis ──────────────────────────────────────────────────────────

    @app.route('/api/lbo/<int:company_id>', methods=['POST'])
    def run_lbo_analysis(company_id):
        """
        Run PE-style LBO model.
        Body: {"entry_multiple": 10, "leverage": 5, "hold_period": 5, "exit_multiple": 10}
        """
        try:
            data = request.json or {}
            conn, ph = _get_db()
            cur = conn.cursor()
            cur.execute(f"""
                SELECT c.name, cf.ebitda, cf.revenue, cf.capex_pct, cf.tax_rate
                FROM companies c
                JOIN company_financials cf ON c.id = cf.company_id
                WHERE c.id = {ph}
            """, (company_id,))
            row = _row_to_dict(cur.fetchone())
            conn.close()

            if not row:
                return jsonify({'error': f'Company {company_id} not found'}), 404

            entry_ebitda = float(row['ebitda'] or 0)
            if entry_ebitda <= 0:
                return jsonify({'error': 'EBITDA must be positive for LBO analysis'}), 400

            revenue = float(row['revenue'] or 1)
            ebitda_margin_entry = entry_ebitda / revenue if revenue > 0 else 0.20

            from lbo_engine import LBOInputs, run_lbo
            entry_mult = float(data.get('entry_multiple', 10.0))
            inputs = LBOInputs(
                entry_ev_ebitda=entry_mult,
                entry_ebitda=entry_ebitda,
                debt_to_ebitda=float(data.get('leverage', 5.0)),
                interest_rate=float(data.get('interest_rate', 0.075)),
                revenue_growth=data.get('revenue_growth', [0.08, 0.07, 0.06, 0.05, 0.05]),
                ebitda_margin_entry=ebitda_margin_entry,
                ebitda_margin_exit=float(data.get('ebitda_margin_exit', ebitda_margin_entry * 1.1)),
                exit_ev_ebitda=float(data.get('exit_multiple', entry_mult)),
                hold_period=int(data.get('hold_period', 5)),
                tax_rate=float(row['tax_rate'] or 0.25),
                capex_pct_revenue=float(row['capex_pct'] or 0.03),
            )
            result = run_lbo(inputs)
            return jsonify(result.to_dict())

        except ValueError as e:
            return jsonify({'error': str(e)}), 400
        except Exception as e:
            logger.error(f'LBO failed for company {company_id}: {e}', exc_info=True)
            return jsonify({'error': str(e)}), 500

    # ── Football Field ────────────────────────────────────────────────────────

    @app.route('/api/company/<int:company_id>/football-field', methods=['GET'])
    def get_football_field(company_id):
        """Return football field valuation ranges with source attribution."""
        try:
            conn, ph = _get_db()
            cur = conn.cursor()
            cur.execute(f"""
                SELECT c.name, c.sector, cf.revenue, cf.ebitda, cf.shares_outstanding,
                       vr.dcf_price_per_share, vr.final_price_per_share,
                       vr.current_price, vr.wacc
                FROM companies c
                JOIN company_financials cf ON c.id = cf.company_id
                LEFT JOIN valuation_results vr ON c.id = vr.company_id
                WHERE c.id = {ph}
                ORDER BY vr.id DESC
                LIMIT 1
            """, (company_id,))
            row = _row_to_dict(cur.fetchone())
            conn.close()

            if not row:
                return jsonify({'error': f'Company {company_id} not found'}), 404

            current_price = float(row.get('current_price') or 0)
            dcf_value = float(row.get('dcf_price_per_share') or 0)

            from football_field import build_football_field
            valuation_results = {
                'dcf_value': dcf_value,
                'fair_value': dcf_value,
                'bear_value': dcf_value * 0.80 if dcf_value else None,
                'bull_value': dcf_value * 1.20 if dcf_value else None,
                'current_price': current_price,
            }
            row['current_price'] = current_price
            result = build_football_field(row, valuation_results)
            return jsonify(result)

        except Exception as e:
            logger.error(f'Football field failed for company {company_id}: {e}')
            return jsonify({'error': str(e)}), 500

    # ── Sensitivity Table ─────────────────────────────────────────────────────

    @app.route('/api/company/<int:company_id>/sensitivity', methods=['GET'])
    def get_sensitivity_table(company_id):
        """2D DCF sensitivity table. Query: ?x=wacc&y=terminal_growth"""
        try:
            conn, ph = _get_db()
            cur = conn.cursor()
            cur.execute(f"""
                SELECT cf.revenue, cf.ebitda, cf.growth_rate_y1, cf.growth_rate_y2,
                       cf.growth_rate_y3, cf.terminal_growth, cf.capex_pct,
                       cf.tax_rate, cf.shares_outstanding, cf.debt, cf.cash,
                       vr.wacc, vr.current_price
                FROM company_financials cf
                LEFT JOIN valuation_results vr ON cf.company_id = vr.company_id
                WHERE cf.company_id = {ph}
                ORDER BY vr.id DESC
                LIMIT 1
            """, (company_id,))
            row = _row_to_dict(cur.fetchone())
            conn.close()

            if not row:
                return jsonify({'error': f'Company {company_id} not found'}), 404

            revenue = float(row['revenue'] or 0)
            ebitda = float(row['ebitda'] or 0)
            wacc = float(row['wacc'] or 0.09)
            terminal_growth = float(row['terminal_growth'] or 0.025)
            capex_pct = float(row['capex_pct'] or 0.05)
            tax_rate = float(row['tax_rate'] or 0.21)
            shares = float(row['shares_outstanding'] or 1)
            net_debt = float(row['debt'] or 0) - float(row['cash'] or 0)
            current_price = float(row['current_price'] or 0)

            growth_rates = [
                float(row['growth_rate_y1'] or 0.08),
                float(row['growth_rate_y2'] or 0.06),
                float(row['growth_rate_y3'] or 0.05),
            ]
            for _ in range(7):
                g = max(terminal_growth, growth_rates[-1] * 0.9)
                growth_rates.append(g)

            ebitda_margin = ebitda / revenue if revenue > 0 else 0.20
            fcfs, rev = [], revenue
            for g in growth_rates:
                rev = rev * (1 + g)
                nopat = rev * ebitda_margin * (1 - tax_rate)
                fcfs.append(nopat - (rev * capex_pct))

            base_inputs = {
                'projected_fcfs': fcfs,
                'shares_outstanding': shares,
                'net_debt': net_debt,
                'wacc': wacc,
                'terminal_growth': terminal_growth,
            }

            from sensitivity import compute_sensitivity_table
            result = compute_sensitivity_table(
                base_inputs, current_price,
                request.args.get('x', 'wacc'),
                request.args.get('y', 'terminal_growth'),
            )
            return jsonify(result)

        except Exception as e:
            logger.error(f'Sensitivity table failed for company {company_id}: {e}')
            return jsonify({'error': str(e)}), 500

