        """Check assumptions for statistical outliers vs sector median."""
        try:
            conn, ph = _get_db()
            cur = conn.cursor()
            cur.execute(f"""
                SELECT c.name, c.sector,
                       cf.revenue, cf.ebitda,
                       cf.growth_rate_y1, cf.terminal_growth, cf.beta,
                       vr.wacc
                FROM companies c
                JOIN company_financials cf ON c.id = cf.company_id
                LEFT JOIN valuation_results vr ON c.id = vr.company_id
                WHERE c.id = {ph}
                ORDER BY vr.id DESC
                LIMIT 1
            """, (company_id,))
            row = _row_to_dict(cur.fetchone())
            conn.close()

            if not row:
                return jsonify({'error': f'Company {company_id} not found'}), 404

            assumptions = {
                'wacc': row.get('wacc'),
                'terminal_growth': row.get('terminal_growth'),
                'revenue': row.get('revenue'),
                'ebitda': row.get('ebitda'),
                'growth_rate_y1': row.get('growth_rate_y1'),
                'beta': row.get('beta'),
            }

            from intelligence.anomaly_detector import analyze_assumptions, get_anomaly_summary
            anomalies = analyze_assumptions(assumptions, row.get('sector', 'default'))
            return jsonify(get_anomaly_summary(anomalies))

        except Exception as e:
            logger.error(f'Anomaly detection failed for company {company_id}: {e}')
            return jsonify({'error': str(e)}), 500

