    # ── Server-Sent Events Live Stream ────────────────────────────────────────

    @app.route('/api/live/stream', methods=['GET'])
    def live_stream():
        """
        SSE stream for live data panel. Sends every 30s.
        Reads from cache only — no new API calls per connected client.
        """
        def generate():
            while True:
                try:
                    payload = {}

                    try:
                        from data_layer import DataLayer
                        dl = DataLayer()
                        rates_raw = dl.get_macro_rates()
                        payload['rates'] = {
                            k: {'value': v.value, 'source': v.source}
                            for k, v in rates_raw.items() if v.available
                        }
                    except Exception:
                        payload['rates'] = {}

                    try:
                        from intelligence.alert_engine import get_alert_count
                        payload['alert_count'] = get_alert_count()
                    except Exception:
                        payload['alert_count'] = 0

                    payload['timestamp'] = datetime.utcnow().isoformat()
                    yield f"data: {json.dumps(payload)}\n\n"

                except GeneratorExit:
                    break
                except Exception as e:
                    yield f"data: {json.dumps({'error': str(e)})}\n\n"

                time.sleep(30)

        return Response(
            generate(),
            mimetype='text/event-stream',
            headers={'Cache-Control': 'no-cache', 'X-Accel-Buffering': 'no'},
        )


