        # ── Portfolio Optimization ─────────────────────────────────────────────────

    @app.route('/api/portfolio/optimize', methods=['POST'])
    def optimize_portfolio():
        """
        Build optimal portfolio from all companies with valuations.
        Uses mean-variance optimization (Markowitz) + valuation conviction weighting.
        """
        try:
            from portfolio_engine import PortfolioEngine, PortfolioConstraints

            body = request.get_json(force=True) or {}
            constraints_raw = body.get('constraints', {})
            target_value = float(body.get('target_value', 1_000_000))

            constraints = PortfolioConstraints(
                max_single_position=constraints_raw.get('max_single_position', 0.20),
                min_single_position=constraints_raw.get('min_single_position', 0.02),
                max_sector_exposure=constraints_raw.get('max_sector_exposure', 0.40),
                risk_tolerance=constraints_raw.get('risk_tolerance', 'Moderate'),
                target_num_holdings=constraints_raw.get('target_num_holdings', 15),
            )

            # Fetch all companies with their latest valuations
            conn, ph = _get_db()
            cur = conn.cursor()
            cur.execute("""
                SELECT c.id, c.name, c.ticker, c.sector,
                       vr.final_price_per_share, vr.current_price,
                       vr.upside_pct, vr.recommendation, vr.wacc,
                       cf.revenue, cf.ebitda, cf.market_cap_estimate,
                       cf.beta, cf.terminal_growth, cf.growth_rate_y1
                FROM companies c
                JOIN company_financials cf ON c.id = cf.company_id
                LEFT JOIN valuation_results vr ON c.id = vr.company_id
                    AND vr.id = (
                        SELECT MAX(id) FROM valuation_results WHERE company_id = c.id
                    )
                ORDER BY c.name
            """)
            rows = [_row_to_dict(r) for r in cur.fetchall()]
            # Phase 0d: map upside_pct -> upside for PortfolioEngine; guard null ticker
            for r in rows:
                r['upside'] = r.get('upside_pct') or 0
                if not r.get('ticker'):
                    r['ticker'] = r.get('name', 'UNKNOWN')[:10]
            conn.close()

            if not rows:
                return jsonify({'error': 'No companies with valuations found'}), 404

            engine = PortfolioEngine()
            allocations, metrics = engine.build_portfolio(rows, constraints, target_value)

            report = engine.generate_portfolio_report(
                allocations, metrics, rows, target_value
            )

            # Compute weighted upside from allocations + company data
            ticker_upside = {r.get('ticker', ''): r.get('upside_pct', 0) or 0 for r in rows}
            weighted_upside = sum(
                allocations.get(t, 0) * ticker_upside.get(t, 0)
                for t in allocations
            )

            return jsonify({
                'allocations': allocations,
                'metrics': {
                    'expected_return': metrics.expected_return,
                    'volatility': metrics.volatility,
                    'sharpe_ratio': metrics.sharpe_ratio,
                    'sortino_ratio': getattr(metrics, 'sortino_ratio', None),
                    'max_drawdown': getattr(metrics, 'max_drawdown', None),
                    'num_holdings': metrics.num_holdings,
                    'sector_breakdown': getattr(metrics, 'sector_concentration', {}),
                    'largest_position': getattr(metrics, 'largest_position', None),
                    'weighted_upside': round(weighted_upside, 2),
                    'total_conviction': getattr(metrics, 'total_conviction_score', None),
                },
                'report': report,
                'generated_at': datetime.utcnow().isoformat(),
            })

        except Exception as e:
            logger.error(f'Portfolio optimization failed: {e}', exc_info=True)
            return jsonify({'error': str(e)}), 500

