    @app.route('/api/company/<int:company_id>/share', methods=['POST'])
    def create_share_link(company_id):
        """Create a shareable read-only link for a company valuation snapshot."""
        try:
            import secrets
            from datetime import timedelta

            # Fetch latest valuation snapshot
            conn, ph = _get_db()
            cur = conn.cursor()
            cur.execute(f"""
                SELECT c.name, c.ticker, c.sector,
                       vr.final_price_per_share, vr.current_price, vr.upside_pct,
                       vr.recommendation, vr.wacc, vr.created_at
                FROM companies c
                LEFT JOIN valuation_results vr ON c.id = vr.company_id
                    AND vr.id = (SELECT MAX(id) FROM valuation_results WHERE company_id = {ph})
                WHERE c.id = {ph}
            """, (company_id, company_id))
            row = cur.fetchone()

            if not row:
                conn.close()
                return jsonify({'error': 'Company not found'}), 404

            snapshot = _row_to_dict(row)
            token = secrets.token_urlsafe(24)
            expires_at = (datetime.utcnow() + timedelta(days=30)).isoformat()

            # Ensure share_links table exists
            cur.execute("""
                CREATE TABLE IF NOT EXISTS share_links (
                    token TEXT PRIMARY KEY,
                    company_id INTEGER,
                    valuation_snapshot TEXT,
                    created_at TEXT,
                    expires_at TEXT,
                    view_count INTEGER DEFAULT 0
                )
            """)
            cur.execute(
                f"INSERT INTO share_links (token, company_id, valuation_snapshot, created_at, expires_at) VALUES ({ph},{ph},{ph},{ph},{ph})",
                (token, company_id, json.dumps(snapshot), datetime.utcnow().isoformat(), expires_at)
            )
            conn.commit()
            conn.close()

            return jsonify({
                'token': token,
                'share_url': f'/share/{token}',
                'expires_at': expires_at,
            })

        except Exception as e:
            logger.error(f'Share link creation failed: {e}', exc_info=True)
            return jsonify({'error': str(e)}), 500

    @app.route('/share/<token>', methods=['GET'])
    def view_share_link(token):
        """Render a read-only valuation view for a shared link."""
        from flask import render_template_string
        try:
            conn, ph = _get_db()
            cur = conn.cursor()
            cur.execute(f"SELECT * FROM share_links WHERE token = {ph}", (token,))
            row = cur.fetchone()
            conn.close()

            if not row:
                return render_template_string(SHARE_NOT_FOUND_HTML, reason='Link not found'), 404

            link = _row_to_dict(row)
            if link['expires_at'] and link['expires_at'] < datetime.utcnow().isoformat():
                return render_template_string(SHARE_NOT_FOUND_HTML, reason='This link has expired'), 410

            # Increment view count
            try:
                conn2, ph2 = _get_db()
                cur2 = conn2.cursor()
                cur2.execute(f"UPDATE share_links SET view_count = view_count + 1 WHERE token = {ph2}", (token,))
                conn2.commit()
                conn2.close()
            except Exception:
                pass

            snapshot = json.loads(link['valuation_snapshot'])
            created_at = link['created_at'][:10] if link['created_at'] else 'Unknown'

            return render_template_string(
                SHARE_VIEW_HTML,
                snapshot=snapshot,
                created_at=created_at,
                view_count=link.get('view_count', 0) + 1,
            )

        except Exception as e:
            logger.error(f'Share link view failed for token {token}: {e}', exc_info=True)
            return render_template_string(SHARE_NOT_FOUND_HTML, reason='An error occurred'), 500


